import pytest
import time
from lru_cache import LRUCache
from threading import Thread

@pytest.mark.asyncio
async def test_lru_ttl_benchmark():
    cache = LRUCache(max_size=10000, ttl_strategy='eager')

    # Simulation de 100 threads avec répartition 70% lecture / 30% écriture
    threads = []
    for i in range(100):
        if i % 10 < 7:
            threads.append(Thread(target=simulate_read, args=(cache,)))
        else:
            threads.append(Thread(target=simulate_write, args=(cache, i)))

    start_time = time.time()
    for t in threads:
        t.start()
    for t in threads:
        t.join()

    duration = time.time() - start_time
    eviction_rate = cache.get_eviction_stats()['rate']

    assert eviction_rate < 0.05, f"Taux d'éviction trop élevé: {eviction_rate}"
    assert duration < 3600, "Benchmark dépassé la durée de 1h"

def simulate_read(cache):
    for _ in range(1000):
        cache.get('key_' + str(_ % 10000))

def simulate_write(cache, thread_id):
    for i in range(100):
        cache.set(f'key_{thread_id}_{i}', f'value_{i}', ttl=3600)

